import sys

n, k = map(int, input().split())
main = list(map(int, input().split()))

graph = [[] for _ in range(n + 1)]

for i in range(1, n + 1):
    if i in main:
        continue
    x = int(input())
    for _ in range(x):
        y = int(input())
        graph[y].append(i)

visited = [False] * (n + 1)

def dfs(node):
    if visited[node]:
        return False
    visited[node] = True
    for neighbor in graph[node]:
        if not dfs(neighbor):
            return False
    return True

for i in range(1, n + 1):
    if i in main:
        continue
    if not dfs(i):
        print(-1)
        sys.exit()

print(n)
print(*main)
